    referenced_ids = set()
    for msg in messages:
        if 'refers_to' in msg.content:
            ref_id = extract_message_id(msg.content)
            referenced_ids.add(ref_id)

    existing_ids = {msg.id for msg in messages}
    drift_score = len(referenced_ids - existing_ids) / len(messages)
