from ag2 import register_message_hook

@register_message_hook
async def ground_conversation_history(message):
    if 'remember when' in message.content.lower() or 'as you said' in message.content.lower():
        # Force agent to requote exact message
        grounded_prompt = f"""Before continuing, QUOTE THE EXACT MESSAGE ID you are referencing:
{message.content}

Only proceed after confirming the message exists in our history."""
        return await message.agent.generate_reply(grounded_prompt)
    return message

from ag2.groupchat import GroupChatManager

class FactCheckSelector(GroupChatManager):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.verified_claims = {}

    def select_speaker(self, last_speaker, selector):
        scores = {}
        for agent in self.agents:
            recent_claims = self.get_recent_claims(agent)
            verification_rate = self.verify_claims(recent_claims)
            scores[agent] = verification_rate

        return max(scores, key=scores.get)

# Replace default selector
groupchat.selector = FactCheckSelector()
